pub fn release(self) {
        // Drop triggers the Drop impl which calls release().
        drop(self);
    }
impl Drop for DepthTensorGuard {
    fn drop(&mut self) {
        Python::with_gil(|py| {
            if let Err(e) = self.py_guard.call_method0(py, "release") {
                log::warn!("TensorGuard.release() failed during drop: {e}");
            }
        });
    }
}
